import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  price: number;
}

export interface InvoiceData {
  invoiceNumber: string;
  date: string;
  dueDate: string;
  senderName: string;
  senderEmail: string;
  senderAddress: string;
  clientName: string;
  clientEmail: string;
  clientAddress: string;
  items: LineItem[];
  taxRate: number;
  notes: string;
  isPaid: boolean;
}

export interface SmartFillResponse {
  items: {
    description: string;
    quantity: number;
    price: number;
  }[];
}

export enum PaymentStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  SUCCESS = 'SUCCESS',
  FAILED = 'FAILED'
}

import { GoogleGenAI, Type } from "@google/genai";
import { SmartFillResponse } from "../types";

const parseInvoiceItems = async (description: string): Promise<SmartFillResponse | null> => {
  if (!process.env.API_KEY) {
    console.warn("API Key is missing for Gemini Service");
    return null;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Extract invoice line items from this text description. If a price or quantity is implied, use reasonable defaults or 1.

      Text: "${description}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  description: { type: Type.STRING, description: "Description of the product or service" },
                  quantity: { type: Type.NUMBER, description: "Quantity sold" },
                  price: { type: Type.NUMBER, description: "Unit price per item" }
                },
                required: ["description", "quantity", "price"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    return JSON.parse(text) as SmartFillResponse;
  } catch (error) {
    console.error("Gemini Parse Error:", error);
    return null;
  }
};

export const geminiService = {
  parseInvoiceItems
};

import React, { useState, useEffect } from 'react';
import { PaymentStatus } from '../types';
import { CreditCard, CheckCircle, Loader2, X } from 'lucide-react';

interface PaymentModalProps {
  amount: number;
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export const PaymentModal: React.FC<PaymentModalProps> = ({ amount, isOpen, onClose, onSuccess }) => {
  const [status, setStatus] = useState<PaymentStatus>(PaymentStatus.IDLE);
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  useEffect(() => {
    if (isOpen) {
      setStatus(PaymentStatus.IDLE);
      setCardNumber('');
      setExpiry('');
      setCvc('');
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handlePay = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus(PaymentStatus.PROCESSING);

    // Simulate network request
    setTimeout(() => {
      setStatus(PaymentStatus.SUCCESS);
      // Wait a bit to show success message before closing/proceeding
      setTimeout(() => {
        onSuccess();
      }, 1500);
    }, 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden relative">

        {/* Close Button */}
        {status !== PaymentStatus.PROCESSING && status !== PaymentStatus.SUCCESS && (
            <button onClick={onClose} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                <X size={24} />
            </button>
        )}

        <div className="bg-slate-50 p-6 border-b border-slate-100">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <CreditCard className="w-6 h-6 text-primary" />
            Secure Payment
          </h2>
          <p className="text-sm text-slate-500 mt-1">Complete your payment to finalize the invoice.</p>
        </div>

        <div className="p-6">
          {status === PaymentStatus.SUCCESS ? (
            <div className="text-center py-8">
              <CheckCircle className="w-16 h-16 text-green-500 mx-auto mb-4 animate-bounce" />
              <h3 className="text-2xl font-bold text-slate-800">Payment Successful!</h3>
              <p className="text-slate-500 mt-2">Generating your invoice now...</p>
            </div>
          ) : (
            <form onSubmit={handlePay} className="space-y-4">
              <div className="bg-blue-50 text-blue-800 p-4 rounded-lg flex justify-between items-center font-semibold">
                <span>Total Amount</span>
                <span className="text-xl">${amount.toFixed(2)}</span>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Card Number</label>
                <input
                  type="text"
                  placeholder="0000 0000 0000 0000"
                  className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all"
                  value={cardNumber}
                  onChange={(e) => setCardNumber(e.target.value)}
                  required
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Expiry Date</label>
                  <input
                    type="text"
                    placeholder="MM/YY"
                    className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all"
                    value={expiry}
                    onChange={(e) => setExpiry(e.target.value)}
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">CVC</label>
                  <input
                    type="text"
                    placeholder="123"
                    className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-primary outline-none transition-all"
                    value={cvc}
                    onChange={(e) => setCvc(e.target.value)}
                    required
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={status === PaymentStatus.PROCESSING}
                className={`w-full py-4 rounded-xl text-white font-bold text-lg shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2 mt-6 ${
                  status === PaymentStatus.PROCESSING 
                    ? 'bg-slate-400 cursor-not-allowed' 
                    : 'bg-primary hover:bg-blue-700 active:scale-95'
                }`}
              >
                {status === PaymentStatus.PROCESSING ? (
                  <>
                    <Loader2 className="w-6 h-6 animate-spin" /> Processing...
                  </>
                ) : (
                  'Pay Now'
                )}
              </button>
            </form>
          )}
        </div>

        <div className="bg-slate-50 p-4 text-center text-xs text-slate-400 border-t border-slate-100">
            Encrypted by 256-bit SSL security. This is a simulation.
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { InvoicePaper } from './components/InvoicePaper';
import { PaymentModal } from './components/PaymentModal';
import { geminiService } from './services/geminiService';
import { InvoiceData, LineItem } from './types';
import { 
  Sparkles, 
  Plus, 
  Trash2, 
  Printer, 
  Download, 
  ChevronRight, 
  CreditCard,
  LayoutTemplate,
  Wand2,
  RefreshCw
} from 'lucide-react';

const INITIAL_DATA: InvoiceData = {
  invoiceNumber: 'INV-001',
  date: new Date().toISOString().split('T')[0],
  dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  senderName: '',
  senderEmail: '',
  senderAddress: '',
  clientName: '',
  clientEmail: '',
  clientAddress: '',
  items: [
    { id: '1', description: 'Web Design Service', quantity: 1, price: 500 }
  ],
  taxRate: 10,
  notes: 'Thank you for your business! Payment is due within 7 days.',
  isPaid: false,
};

function App() {
  const [data, setData] = useState<InvoiceData>(INITIAL_DATA);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [smartFillText, setSmartFillText] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');

  const updateField = (field: keyof InvoiceData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const addItem = () => {
    const newItem: LineItem = {
      id: Math.random().toString(36).substr(2, 9),
      description: '',
      quantity: 1,
      price: 0
    };
    setData(prev => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof LineItem, value: any) => {
    setData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const removeItem = (id: string) => {
    setData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleSmartFill = async () => {
    if (!smartFillText.trim()) return;
    setIsThinking(true);
    const result = await geminiService.parseInvoiceItems(smartFillText);
    if (result && result.items) {
      const newItems = result.items.map(item => ({
        id: Math.random().toString(36).substr(2, 9),
        description: item.description,
        quantity: item.quantity,
        price: item.price
      }));
      setData(prev => ({ ...prev, items: [...prev.items, ...newItems] }));
      setSmartFillText('');
    }
    setIsThinking(false);
  };

  const getTotal = () => {
    const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.price), 0);
    const tax = subtotal * (data.taxRate / 100);
    return subtotal + tax;
  };

  const handlePaymentSuccess = () => {
    setData(prev => ({ ...prev, isPaid: true }));
    setIsPaymentModalOpen(false);
    setActiveTab('preview');
  };

  // Helper to handle print
  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col md:flex-row print:bg-white">

      {/* --- Sidebar / Editor (Hidden on print) --- */}
      <div className={`no-print w-full md:w-[450px] lg:w-[500px] bg-white border-r border-slate-200 h-auto md:h-screen overflow-y-auto flex-shrink-0 flex flex-col transition-all duration-300 ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}`}>

        <div className="p-6 border-b border-slate-100 sticky top-0 bg-white z-20">
            <div className="flex items-center gap-2 mb-1">
                <LayoutTemplate className="w-6 h-6 text-primary" />
                <h1 className="text-2xl font-bold tracking-tight text-slate-900">SmartInvoice</h1>
            </div>
            <p className="text-sm text-slate-500">AI-Powered Invoice Generator</p>
        </div>

        <div className="p-6 space-y-8 pb-32">

          {/* Smart Fill Section */}
          <div className="bg-indigo-50 rounded-xl p-4 border border-indigo-100">
            <div className="flex items-center gap-2 mb-2 text-indigo-900 font-semibold">
                <Sparkles className="w-4 h-4" />
                <span>AI Smart Fill</span>
            </div>
            <textarea 
                className="w-full text-sm p-3 rounded-lg border-indigo-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none bg-white"
                rows={3}
                placeholder="e.g., I redesigned the website landing page for 10 hours at $80/hr and sold a logo package for $300."
                value={smartFillText}
                onChange={(e) => setSmartFillText(e.target.value)}
            />
            <button 
                onClick={handleSmartFill}
                disabled={isThinking || !smartFillText}
                className="mt-3 w-full py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center gap-2 transition-colors"
            >
                {isThinking ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                {isThinking ? 'Parsing...' : 'Generate Items with AI'}
            </button>
          </div>

          {/* Basic Info */}
          <section className="space-y-4">
            <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Invoice Details</h3>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-medium text-slate-500 mb-1">Number</label>
                    <input type="text" value={data.invoiceNumber} onChange={(e) => updateField('invoiceNumber', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
                </div>
                <div>
                    <label className="block text-xs font-medium text-slate-500 mb-1">Date</label>
                    <input type="date" value={data.date} onChange={(e) => updateField('date', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
                </div>
            </div>
          </section>

          {/* Sender Info */}
          <section className="space-y-4">
            <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">From (You)</h3>
            <input type="text" placeholder="Your Name / Business" value={data.senderName} onChange={(e) => updateField('senderName', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
            <input type="email" placeholder="Email Address" value={data.senderEmail} onChange={(e) => updateField('senderEmail', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
            <textarea placeholder="Address" value={data.senderAddress} onChange={(e) => updateField('senderAddress', e.target.value)} className="w-full p-2 text-sm border rounded-md h-20 resize-none" />
          </section>

          {/* Client Info */}
          <section className="space-y-4">
            <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Bill To (Client)</h3>
            <input type="text" placeholder="Client Name" value={data.clientName} onChange={(e) => updateField('clientName', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
            <input type="email" placeholder="Client Email" value={data.clientEmail} onChange={(e) => updateField('clientEmail', e.target.value)} className="w-full p-2 text-sm border rounded-md" />
            <textarea placeholder="Client Address" value={data.clientAddress} onChange={(e) => updateField('clientAddress', e.target.value)} className="w-full p-2 text-sm border rounded-md h-20 resize-none" />
          </section>

          {/* Items */}
          <section className="space-y-4">
            <div className="flex justify-between items-center">
                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Line Items</h3>
                <button onClick={addItem} className="text-xs text-primary font-medium hover:underline flex items-center gap-1">
                    <Plus size={14} /> Add Item
                </button>
            </div>
            <div className="space-y-3">
                {data.items.map((item) => (
                    <div key={item.id} className="p-3 bg-white border border-slate-200 rounded-lg shadow-sm group">
                        <div className="flex gap-2 mb-2">
                            <input 
                                type="text" 
                                placeholder="Description" 
                                value={item.description} 
                                onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                                className="flex-1 p-1 text-sm border-b border-transparent focus:border-primary outline-none font-medium"
                            />
                            <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 transition-colors">
                                <Trash2 size={16} />
                            </button>
                        </div>
                        <div className="flex gap-4">
                            <div className="w-20">
                                <label className="text-[10px] text-slate-400 block">Qty</label>
                                <input 
                                    type="number" 
                                    value={item.quantity} 
                                    onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value) || 0)}
                                    className="w-full text-sm outline-none bg-slate-50 rounded px-1"
                                />
                            </div>
                            <div className="w-24">
                                <label className="text-[10px] text-slate-400 block">Price</label>
                                <div className="flex items-center">
                                    <span className="text-xs text-slate-400 mr-1">$</span>
                                    <input 
                                        type="number" 
                                        value={item.price} 
                                        onChange={(e) => updateItem(item.id, 'price', parseFloat(e.target.value) || 0)}
                                        className="w-full text-sm outline-none bg-slate-50 rounded px-1"
                                    />
                                </div>
                            </div>
                            <div className="flex-1 text-right">
                                <label className="text-[10px] text-slate-400 block">Total</label>
                                <span className="text-sm font-bold text-slate-700">${(item.quantity * item.price).toFixed(2)}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
          </section>

          {/* Settings */}
          <section className="space-y-4">
             <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-slate-600">Tax Rate (%)</label>
                <input 
                    type="number" 
                    value={data.taxRate} 
                    onChange={(e) => updateField('taxRate', parseFloat(e.target.value) || 0)}
                    className="w-20 p-2 text-right text-sm border rounded-md"
                />
             </div>
             <div>
                <label className="text-sm font-medium text-slate-600 block mb-2">Notes</label>
                <textarea 
                    value={data.notes} 
                    onChange={(e) => updateField('notes', e.target.value)} 
                    className="w-full p-2 text-sm border rounded-md h-24 resize-none"
                />
             </div>
          </section>

        </div>

        {/* Mobile Tab Switcher */}
        <div className="md:hidden sticky bottom-0 left-0 right-0 bg-white border-t p-4 flex gap-4 z-30">
            <button 
                onClick={() => setActiveTab('preview')}
                className="flex-1 py-3 bg-primary text-white rounded-lg font-semibold shadow-lg flex items-center justify-center gap-2"
            >
                Preview Invoice <ChevronRight size={18} />
            </button>
        </div>
      </div>

      {/* --- Preview / Action Area --- */}
      <div className={`flex-1 relative bg-slate-200/50 flex flex-col h-screen overflow-hidden ${activeTab === 'edit' ? 'hidden md:flex' : 'flex fixed inset-0 z-40 md:static'}`}>

        {/* Toolbar */}
        <div className="no-print h-16 bg-white/80 backdrop-blur border-b border-slate-200 flex items-center justify-between px-4 md:px-8 z-20">
            <button 
                onClick={() => setActiveTab('edit')} 
                className="md:hidden text-slate-600 text-sm font-medium"
            >
                ← Back to Edit
            </button>
            <div className="hidden md:block text-slate-500 text-sm">
                Live Preview
            </div>

            <div className="flex gap-3">
                {data.isPaid ? (
                     <button 
                     onClick={handlePrint}
                     className="px-4 py-2 bg-slate-800 text-white rounded-lg text-sm font-medium hover:bg-slate-900 transition-colors flex items-center gap-2 shadow-lg"
                 >
                     <Printer size={16} /> Print / Download PDF
                 </button>
                ) : (
                    <button 
                        onClick={() => setIsPaymentModalOpen(true)}
                        className="px-6 py-2 bg-green-600 text-white rounded-lg text-sm font-bold hover:bg-green-700 transition-colors shadow-lg shadow-green-600/20 flex items-center gap-2 animate-pulse"
                    >
                        <CreditCard size={16} /> Pay to Finalize
                    </button>
                )}
            </div>
        </div>

        {/* Invoice Scroll Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 flex justify-center items-start print:p-0 print:overflow-visible print:block">
            <div className="scale-[0.8] md:scale-100 origin-top print:transform-none transition-transform duration-300">
                <InvoicePaper data={data} />
            </div>
        </div>

      </div>

      {/* Modals */}
      <PaymentModal 
        amount={getTotal()}
        isOpen={isPaymentModalOpen}
        onClose={() => setIsPaymentModalOpen(false)}
        onSuccess={handlePaymentSuccess}
      />

    </div>
  );
}

