  senderPan: 'AAHCI4821K',
  senderCin: 'U62099KA2024PTC183531',

  clientName: 'Bhoomika',
  clientAddress: 'Bengaluru, Karnataka',
  clientEmail: '',
  clientPhone: '91- 98867 68322',
  clientGstin: 'NA',
  clientStateCode: '29',

