  const addItem = () => {
    const newItem: LineItem = {
      id: Math.random().toString(36).substr(2, 9),
      description: '',
      hsnCode: '',
      quantity: 1,
      unit: 'No',
      price: 0
    };
    setData(prev => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof LineItem, value: any) => {
    setData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  // Special handler for "Total" input to reverse-calculate the Price (Taxable Value)
  const updateItemTotal = (id: string, totalAmount: number) => {
    // Logic: Total = (Price * Qty) * (1 + TaxRate/100)
    // We assume Qty is usually 1 for this calculation context, or we solve for Price
    const item = data.items.find(i => i.id === id);
    if (!item) return;

    // Avoid division by zero
    const qty = item.quantity || 1;
    const taxMultiplier = 1 + (data.taxRate / 100);

    // Calculate Unit Price (Taxable Value)
    // Formula: Price = (Total / TaxMultiplier) / Qty
    const rawPrice = (totalAmount / taxMultiplier) / qty;

    // Round to integer as per screenshot (25000 -> 21186)
    const roundedPrice = Math.round(rawPrice);

    updateItem(id, 'price', roundedPrice);
  };

  const removeItem = (id: string) => {
    setData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
