  const handleSmartFill = async () => {
    if (!smartFillText.trim()) return;
    setIsThinking(true);
    const result = await geminiService.parseInvoiceItems(smartFillText);
    if (result && result.items) {
      const newItems = result.items.map(item => ({
        id: Math.random().toString(36).substr(2, 9),
        description: item.description,
        hsnCode: '',
        quantity: item.quantity,
        unit: 'No',
        price: item.price // Note: Gemini might return total, user might need to adjust manually if strict reverse calc is needed for AI items
      }));
      setData(prev => ({ ...prev, items: [...prev.items, ...newItems] }));
      setSmartFillText('');
    }
    setIsThinking(false);
  };

  const getTotal = () => {
    const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.price), 0);
    const tax = subtotal * (data.taxRate / 100);
