    // Math matching the screenshot:
    // Rate in table = item.price (Taxable Value)
    // CGST Value = Rate * 9%
    // SGST Value = Rate * 9%
    // Total = Rate + CGST + SGST

    // Using Math.round to match screenshot integer values for display if needed
    // The screenshot shows integers for 21186, 1907, 25000.

    const taxableValue = item.price * item.quantity;
    const cgstVal = Math.round(taxableValue * (taxRateSplit / 100));
    const sgstVal = Math.round(taxableValue * (taxRateSplit / 100));
    const total = taxableValue + cgstVal + sgstVal;

