  useEffect(() => {
    setData(prev => ({ ...prev, invoiceNumber: getNextInvoiceNumber() }));
  }, []);

  const updateField = (field: keyof InvoiceData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const addItem = () => {
    const newItem: LineItem = {
      id: Math.random().toString(36).substr(2, 9),
      description: '',
      hsnCode: '',
      quantity: 1,
      unit: 'No',
      price: 0
    };
    setData(prev => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof LineItem, value: any) => {
    setData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  // Fixed Logic: Allows precise decimals so Total doesn't jump
  const updateItemTotal = (id: string, totalAmount: number) => {
    const item = data.items.find(i => i.id === id);
    if (!item) return;

    const qty = item.quantity || 1;
    const taxMultiplier = 1 + (data.taxRate / 100);

    // Formula: Price = (Total / TaxMultiplier) / Qty
    const rawPrice = (totalAmount / taxMultiplier) / qty;

    // Keep 4 decimal places for internal precision, this prevents "3 -> 4" rounding errors
    const precisePrice = parseFloat(rawPrice.toFixed(4));

    updateItem(id, 'price', precisePrice);
  };

  const removeItem = (id: string) => {
    setData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleSmartFill = async () => {
    if (!smartFillText.trim()) return;
    setIsThinking(true);
    const result = await geminiService.parseInvoiceItems(smartFillText);
    if (result && result.items) {
      const newItems = result.items.map(item => ({
        id: Math.random().toString(36).substr(2, 9),
        description: item.description,
        hsnCode: '',
        quantity: item.quantity,
        unit: 'No',
        price: item.price 
      }));
      setData(prev => ({ ...prev, items: [...prev.items, ...newItems] }));
      setSmartFillText('');
    }
    setIsThinking(false);
  };

  const getTotal = () => {
    const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.price), 0);
    const tax = subtotal * (data.taxRate / 100);
    return subtotal + tax; 
  };

  const handlePaymentSuccess = () => {
    setData(prev => ({ ...prev, isPaid: true }));
    setIsPaymentModalOpen(false);
    setActiveTab('preview');
