  }, []);

  // Update document title for download filename
  useEffect(() => {
    if (data.invoiceNumber) {
      document.title = `Invoice-${data.invoiceNumber}`;
    }
  }, [data.invoiceNumber]);

  const updateField = (field: keyof InvoiceData, value: any) => {
