                <div className="text-right w-full pt-16">
                    Authorised Signatory
                </div>
            </div>
        </div>
      </div>

      <div className="text-center text-[8px] mt-1 print:hidden">Generated by SmartInvoice AI</div>
    </div>
  );
};

import React from 'react';
