      {/* --- Preview / Action Area --- */}
      <div className={`flex-1 relative bg-slate-300 flex flex-col h-screen overflow-hidden ${activeTab === 'edit' ? 'hidden md:flex' : 'flex fixed inset-0 z-40 md:static'}`}>

